calls.raw_output:
{
  "canary_id": "kidde_nc_internal_fault_startup",
  "adequacy": "SUFFICIENT",
  "question": "Al energizar una central Kidde NC que ha detectado una avería interna, ¿cómo identifico la secuencia especial de inicio por los dos LED, qué credencial y mando debo usar para restablecerla y qué ocurre si la avería persiste?",
  "expected_behavior": "answer",
  "gold_answer": "Es la secuencia especial de inicio de avería utilizada después de que la central detecte una avería interna. Se reconoce porque el LED general «Avería» parpadea rápidamente y el LED «Avería sistema» parpadea lentamente. Para intentar restablecer la central, introduzca primero la contraseña del nivel de usuario operador y después pulse «Rearme». Si el estado de avería continúa, la central cancela la secuencia de inicio y enciende el LED «Avería sistema»; en ese caso deben comprobarse todas las conexiones y la configuración de la central.",
  "atomic_facts": [
    {
      "fact_id": "F01",
      "text": "La secuencia especial de inicio de avería se utiliza después de que la central haya detectado una avería interna.",
      "type": "core",
      "state": "present",
      "value": "Secuencia especial posterior a la detección de una avería interna",
      "citations": [
        {
          "pdf": "bcn-3100017-es_r002_nc_series_fire_alarm_control_panel_installation_manual.pdf",
          "page": 89
        }
      ],
      "visual_evidence": [
        {
          "page": 89,
          "evidence": "Bajo el encabezado «Inicio de avería», la primera frase describe una secuencia especial usada tras detectar una avería interna."
        }
      ]
    },
